// Use the standard library implementation when available.
#if defined(__cpp_lib_source_location) && __cpp_lib_source_location >= 201907L
#  define MLN_HAS_STD_SOURCE_LOCATION 1
#endif

namespace mbgl {

#if MLN_HAS_STD_SOURCE_LOCATION

using source_location = std::source_location;

#else

class source_location {
public:
    using line_type = std::uint_least32_t;
    using column_type = std::uint_least32_t;

    constexpr source_location() noexcept
        : file_name_(nullptr), function_name_(nullptr), line_(0), column_(0) {}

    static constexpr source_location current(const char* file = __FILE__,
                                              const char* function = __FUNCTION__,
                                              line_type line = __LINE__,
                                              column_type column = 0) noexcept {
        return source_location(file, function, line, column);
    }

    constexpr line_type line() const noexcept { return line_; }
    constexpr column_type column() const noexcept { return column_; }
    constexpr const char* file_name() const noexcept { return file_name_; }
    constexpr const char* function_name() const noexcept { return function_name_; }

private:
    constexpr source_location(const char* file,
                              const char* function,
                              line_type line,
                              column_type column) noexcept
        : file_name_(file), function_name_(function), line_(line), column_(column) {}

    const char* file_name_;
    const char* function_name_;
    line_type line_;
    line_type column_;
};

#endif

} // namespace mbgl

#if MLN_HAS_STD_SOURCE_LOCATION
#  define MLN_SOURCE_LOCATION_CURRENT() ::mbgl::source_location::current()
#else
#  define MLN_SOURCE_LOCATION_CURRENT() ::mbgl::source_location::current(__FILE__, __FUNCTION__, __LINE__)
#endif
```

Wait: The static `current()` with default args might be problematic for `__FUNCTION__` as a default argument. As discussed, `__FUNCTION__` is not a macro, it's a function-local variable. In default arguments, cannot refer to local variables. But because it's a magic variable? Let's test with a simple compile. However, even if it compiles, it would return the function name of `current()` itself, not the caller? Actually the default argument expression `__FUNCTION__` is evaluated at the point of the function call, but `__FUNCTION__` expands to the name of the function containing the call. So in `current()` call, it should be the caller's function name. But is it allowed as a default argument? I think `__FUNCTION__` is not allowed in default arguments because it is not a constant expression? Let's test with small program.

