#pragma once

#include <cstdint>

#if defined(__has_include)
#  if __has_include(<source_location>)
#    include <source_location>
#  endif
#endif

// Use the standard library implementation when it is actually available.
#if defined(__cpp_lib_source_location) && __cpp_lib_source_location >= 201907L
#  define MLN_HAS_STD_SOURCE_LOCATION 1
#endif

namespace mbgl {

#if MLN_HAS_STD_SOURCE_LOCATION

using source_location = std::source_location;

#else

/// A lightweight, standards-safe fallback for `std::source_location` for toolchains
/// and standard libraries that do not yet provide it (e.g. OpenHarmony's C++ runtime).
class source_location {
public:
    using line_type = std::uint_least32_t;
    using column_type = std::uint_least32_t;

    constexpr source_location() noexcept
        : file_name_(nullptr),
          function_name_(nullptr),
          line_(0),
          column_(0) {}

    constexpr source_location(const char* file_name,
                              const char* function_name,
                              line_type line,
                              column_type column = 0) noexcept
        : file_name_(file_name),
          function_name_(function_name),
          line_(line),
          column_(column) {}

    constexpr line_type line() const noexcept { return line_; }
    constexpr column_type column() const noexcept { return column_; }
    constexpr const char* file_name() const noexcept { return file_name_; }
    constexpr const char* function_name() const noexcept { return function_name_; }

private:
    const char* file_name_;
    const char* function_name_;
    line_type line_;
    column_type column_;
};

#endif

} // namespace mbgl

/// Captures the current source location.
///
/// When `std::source_location` is available this expands to the standard
/// `::mbgl::source_location::current()`.  On toolchains without it (e.g.
/// OpenHarmony) it expands to a fallback constructed from `__FILE__`,
/// `__FUNCTION__` and `__LINE__` at the call site, preserving useful diagnostic
/// information.
#if MLN_HAS_STD_SOURCE_LOCATION
#  define MLN_SOURCE_LOCATION_CURRENT() (::mbgl::source_location::current())
#else
#  define MLN_SOURCE_LOCATION_CURRENT() (::mbgl::source_location(__FILE__, __FUNCTION__, __LINE__))
#endif

